#[test]
fn test_rich_logging_integrates_with_console() {
    let tc = TestConsole::new_rich();

    // Initialize logging to capture to test console
    let subscriber = RichSubscriberBuilder::new()
        .with_writer(tc.writer())
        .build();

    tracing::subscriber::with_default(subscriber, || {
        tracing::info!("Test log message");
        tracing::error!("Test error");
    });

    tc.assert_contains("Test log message");
    tc.assert_contains("Test error");
}
